    def test_json_output_does_not_create_file(self, tmp_path: Path, capsys) -> None:
        output_path = tmp_path / "support-bundle.zip"

        with (
            patch(
                "scc_cli.commands.support.build_default_support_bundle_dependencies",
                return_value=object(),
